import { z } from 'zod';
export const supplierSchema = z.object({ supplier_code:z.string().trim().min(1).max(50), company_name:z.string().trim().min(1).max(200), tax_number:z.string().max(80).optional(), registration_number:z.string().max(100).optional(), address:z.string().max(500).optional(), city:z.string().max(120).optional(), country:z.string().max(120).optional(), contact_person:z.string().max(200).optional(), phone:z.string().max(50).optional(), email:z.union([z.string().email(),z.literal('')]).optional(), website:z.union([z.string().url(),z.literal('')]).optional(), payment_terms:z.string().max(100).optional(), currency:z.string().regex(/^[A-Za-z]{3}$/), notes:z.string().max(10000).optional(), status:z.enum(['active','inactive','on_hold']), category_ids:z.array(z.number().int().positive()) });
export const contactSchema = z.object({ name:z.string().trim().min(1).max(200), department:z.string().max(120).optional(), job_title:z.string().max(120).optional(), phone:z.string().max(50).optional(), email:z.union([z.string().email(),z.literal('')]).optional(), is_primary:z.boolean(), is_emergency:z.boolean(), notes:z.string().max(1000).optional() });
export const contractSchema = z.object({ contract_number:z.string().trim().min(1).max(80), start_date:z.string().min(1), end_date:z.string().min(1), renewal_date:z.string().optional(), contract_value:z.coerce.number().min(0), currency:z.string().regex(/^[A-Za-z]{3}$/), status:z.enum(['draft','active','expired','terminated','renewed']), attachment_name:z.string().max(255).optional(), attachment_reference:z.string().max(500).optional(), notes:z.string().max(10000).optional() }).refine(x=>x.end_date>=x.start_date,{path:['end_date'],message:'End date cannot be before start date.'});
export const quotationSchema = z.object({ quotation_number:z.string().trim().min(1).max(100), rfq_reference:z.string().max(100).optional(), quotation_date:z.string().min(1), valid_until:z.string().optional(), currency:z.string().regex(/^[A-Za-z]{3}$/), tax_amount:z.coerce.number().min(0), status:z.enum(['draft','received','under_review','accepted','rejected','expired']), notes:z.string().max(10000).optional(), items:z.array(z.object({ product_id:z.preprocess(v=>v===''||v===null||v===undefined?null:v,z.coerce.number().int().positive().nullable()), description:z.string().trim().min(1).max(500), quantity:z.coerce.number().positive(), unit_price:z.coerce.number().min(0), lead_time_days:z.preprocess(v=>v===''||v===null||v===undefined?null:v,z.coerce.number().int().min(0).nullable()) })).min(1) });
export const ratingSchema = z.object({ review_period_start:z.string().min(1), review_period_end:z.string().min(1), product_quality_score:z.coerce.number().min(0).max(5), currency:z.string().regex(/^[A-Za-z]{3}$/), notes:z.string().max(10000).optional() }).refine(x=>x.review_period_end>=x.review_period_start,{path:['review_period_end'],message:'Review end cannot be before start.'});
